async function main() {
  console.log(`Seeding ${foods.length} food items…`);

  let created = 0;
  let skipped = 0;

  for (const food of foods) {
    try {
      await prisma.foodItem.upsert({
        where: { name: food.name },
        update: {},
        create: {
          name: food.name,
          category: food.category,
          mealTypes: j(food.mealTypes),
          ageGroups: j(food.ageGroups),
          allergens: j(food.allergens),
          preferences: j(food.preferences),
          description: food.description,
        },
      });
      created++;
    } catch (e) {
      console.warn(`Skipped: ${food.name}`);
      skipped++;
    }
  }

  console.log(`Done. Created/updated: ${created}, skipped: ${skipped}`);
  console.log(`Total food items in DB: ${await prisma.foodItem.count()}`);
}

main().catch(console.error).finally(() => prisma.$disconnect());
